-- =====================================================================
-- VERIFICATION
-- =====================================================================
SELECT 'organizations' AS entity, COUNT(*) AS total FROM organizations
UNION ALL SELECT 'org_members', COUNT(*) FROM org_members
UNION ALL SELECT 'clusters', COUNT(*) FROM clusters
UNION ALL SELECT 'projects', COUNT(*) FROM projects
UNION ALL SELECT 'environments', COUNT(*) FROM environments
UNION ALL SELECT 'containers', COUNT(*) FROM containers;

SELECT o.name AS org, COUNT(c.id) AS containers
FROM organizations o
LEFT JOIN containers c ON c.org_id = o.id
GROUP BY o.name
ORDER BY containers DESC;

COMMIT;
